<span class="line">  <span class="token keyword">const</span> items <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&#39;苹果&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;香蕉&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;橙子&#39;</span><span class="token punctuation">]</span></span>
